import { useEffect, useRef } from 'react';

const GraphBlock = () => {
	
	const canvasRef = useRef(null);
	
	function drawBase(ctx, width, height) {
	  const cx = width / 2;
	  const cy = height / 2;
	  const R = 100;

	  ctx.clearRect(0, 0, width, height);

	  // Оси
	  ctx.strokeStyle = 'black';
	  ctx.beginPath();
	  ctx.moveTo(0, cy);
	  ctx.lineTo(width, cy);
	  ctx.moveTo(cx, 0);
	  ctx.lineTo(cx, height);
	  ctx.stroke();

	  ctx.fillStyle = 'rgba(0, 0, 255, 0.5)';

	  // Квадрат
	  ctx.fillRect(cx, cy - R / 2, R, R / 2);

	  // Треугольник
	  ctx.beginPath();
	  ctx.moveTo(cx, cy);
	  ctx.lineTo(cx - R, cy);
	  ctx.lineTo(cx, cy + R);
	  ctx.closePath();
	  ctx.fill();

	  // Четверть круга
	  ctx.beginPath();
	  ctx.arc(cx, cy, R / 2, 0, Math.PI / 2);
	  ctx.lineTo(cx, cy);
	  ctx.fill();
	}
	
	useEffect( () => {
		const canvas = canvasRef.current;
		if (!canvas) return;
		
		const ctx = canvas.getContext('2d');
		
		drawBase(ctx, canvas.width, canvas.height);
	}, []);
  
	return (
		<canvas
			ref={canvasRef}
			width={500}
			height={500}
			className="graph"
		/>
	);
};

export default GraphBlock;
